// Plan builder — emits every shell command for this job.
//
// Pipeline stages:
//   1. Download clips — always.
//   2. Download music + voice + avatar — only when respective toggle ON and URL ready.
//  *3. Normalize clips → uniform profile → concat demuxer → silent.mp4 (video + silent AAC).
//   4. Mix — one of 4 scenarios (none / music-only / voice-only / both), all with fade-outs.
//   5. Avatar overlay (optional) — chromakey greenscreen + overlay onto base video.
//      ffmpeg flags copied VERBATIM from CFTG/Combine - 9.json lines ~70-76: chromakey=0x79ff9b:0.12:0.05,
//      despill=type=green:mix=0.5, scale=400:-2, overlay=W-w-40:H-h. Do NOT tune without a live test.
//   6. Upload final.mp4 to MinIO.
//
// Fade-outs: music 1.5s tail (cinematic), voice 0.5s tail (graceful cut if overshoot).
const row = $json;
let items = [];
try { items = JSON.parse(row.items_json || '[]'); } catch (_) { items = []; }
const valid = items.filter(it => it && it.video_url && /^https?:\/\//.test(it.video_url));

if (valid.length === 0) {
  return [{ json: { valid: false, job_id: row.job_id, user_id: row.user_id, error: 'No clips with a usable video_url in this job.' } }];
}

const jobId = row.job_id;
const tmpDir = `/tmp/goodini/${jobId}`;
const silentPath = `${tmpDir}/silent.mp4`;
const preOverlayPath = `${tmpDir}/with_audio.mp4`;
const outPath = `${tmpDir}/final.mp4`;
const musicPath = `${tmpDir}/music.mp3`;
const voicePath = `${tmpDir}/voice.mp3`;
const avatarPath = `${tmpDir}/avatar.mp4`;

const shq = (s) => `'${String(s).replace(/'/g, "'\\''")}'`;

const hasMusic = row.music_enabled === true && row.music_url && /^https?:\/\//.test(row.music_url);
const hasVoice = row.voice_enabled === true && row.voice_audio_url && /^https?:\/\//.test(row.voice_audio_url);
const hasAvatar = row.avatar_enabled === true && row.avatar_url && /^https?:\/\//.test(row.avatar_url);

// Aspect ratio — single value per montage (frontend blocks mixing 16:9 + 9:16).
// Drives output canvas size and avatar overlay scale. 16:9 → 1920x1080 + avatar 550.
// 9:16 → 1080x1920 + avatar 450. Defaults to 16:9 if column is null (legacy rows).
const isPortrait = row.aspect_ratio === '9:16';
const OUT_W = isPortrait ? 1080 : 1920;
const OUT_H = isPortrait ? 1920 : 1080;
const AVATAR_SCALE = isPortrait ? 450 : 550;

// When avatar is ON, mix output goes to with_audio.mp4 (intermediate), then overlay step produces final.mp4.
// When avatar is OFF, mix output goes straight to final.mp4 (single-stage, as before).
const mixOutPath = hasAvatar ? preOverlayPath : outPath;

// Stage 1 — parallel download (clips + optional music + optional voice + optional avatar).
const downloads = valid.map((it, i) =>
  `curl -sfL --retry 3 --retry-delay 2 -o ${tmpDir}/clip${i}.mp4 ${shq(it.video_url)}`
).join(' && ');
const prepareInner = `mkdir -p ${tmpDir} && ${downloads}`;
const downloadMusicInner = hasMusic
  ? `curl -sfL --retry 3 --retry-delay 2 -o ${musicPath} ${shq(row.music_url)}`
  : '';
const downloadVoiceInner = hasVoice
  ? `curl -sfL --retry 3 --retry-delay 2 -o ${voicePath} ${shq(row.voice_audio_url)}`
  : '';
const downloadAvatarInner = hasAvatar
  ? `curl -sfL --retry 3 --retry-delay 2 -o ${avatarPath} ${shq(row.avatar_url)}`
  : '';

// Stage 2 — single-pass filter_complex concat. No per-clip normalize, no concat demuxer.
// Reads raw source clips, re-encodes into one continuous timeline with libx264 + silent AAC.
// This eliminates DTS discontinuities at clip boundaries that caused avatar overlay freezes.
const inputs = valid.map((_, i) => `-i ${tmpDir}/clip${i}.mp4`).join(' ');
const n = valid.length;
const vfChain = valid.map((_, i) =>
  `[${i}:v]scale=${OUT_W}:${OUT_H}:force_original_aspect_ratio=decrease,pad=${OUT_W}:${OUT_H}:(ow-iw)/2:(oh-ih)/2,setsar=1,fps=30,format=yuv420p[v${i}]`
).join(';');
const concatLabels = valid.map((_, i) => `[v${i}]`).join('');
const filterComplex = `${vfChain};${concatLabels}concat=n=${n}:v=1:a=0[vout]`;
const renderInner = [
  '/usr/bin/ffmpeg -y -hide_banner -loglevel error',
  inputs,
  '-f lavfi -i anullsrc=channel_layout=stereo:sample_rate=48000',
  `-filter_complex ${shq(filterComplex)}`,
  '-map "[vout]" -map ' + n + ':a',
  '-c:v libx264 -preset veryfast -crf 20 -pix_fmt yuv420p',
  '-c:a aac -b:a 192k -ar 48000 -ac 2',
  '-shortest -movflags +faststart',
  silentPath
].join(' ');
const probeInner = `/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${outPath}`;

//*Stage 3 — mix. Four scenarios:
//  A) no audio  → mv silent → final
//  B) music only → amix(silent_audio, music w/ volume 0.3 + afade 1.5s tail)
//  C) voice only → amix(silent_audio, voice w/ afade 0.5s tail)
//  D) music + voice → amix(silent_audio, music 0.3 + fade, voice + fade)
// FADE_M = max(0, duration - 1.5); FADE_V = max(0, duration - 0.5). Computed
// via shell && chain (not variable-prefix syntax — siblings can't see each other).
let mixInner;
if (!hasMusic && !hasVoice) {
  mixInner = `mv ${silentPath} ${mixOutPath}`;
} else if (hasMusic && !hasVoice) {
  mixInner = [
    `FADE_M=$(/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${silentPath} | awk -F. '{f=$1-1.5; if(f<0) f=0; print f; exit}')`,
    '&&',
    '/usr/bin/ffmpeg -y -hide_banner -loglevel error',
    `-i ${silentPath} -i ${musicPath}`,
    '-filter_complex "[1:a]volume=0.3,afade=t=out:st=$FADE_M:d=1.5[bg];[0:a][bg]amix=inputs=2:duration=first:normalize=0[mix]"',
    '-map 0:v -map "[mix]" -c:v copy -c:a aac -b:a 192k -shortest -movflags +faststart',
    mixOutPath
  ].join(' ');
} else if (!hasMusic && hasVoice) {
  // atempo auto-fit 2026-04-19: if voice.mp3 is longer than silent video, speed it
  // up to fit. Clamp RATIO to [1.0, 1.10]. <1.0 = voice already shorter, leave alone.
  // >1.10 = chipmunk territory, cap at 1.10 and let -shortest trim the residual tail.
  mixInner = [
    `VIDEO_DUR=$(/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${silentPath})`,
    '&&',
    `VOICE_DUR=$(/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${voicePath})`,
    '&&',
    'RATIO=$(awk "BEGIN{r=$VOICE_DUR/$VIDEO_DUR; if(r<1.0) r=1.0; if(r>1.10) r=1.10; printf \\"%.4f\\", r}")',
    '&&',
    'FADE_V=$(awk "BEGIN{f=$VIDEO_DUR-0.5; if(f<0) f=0; printf \\"%.3f\\", f}")',
    '&&',
    '/usr/bin/ffmpeg -y -hide_banner -loglevel error',
    `-i ${silentPath} -i ${voicePath}`,
    '-filter_complex "[1:a]atempo=$RATIO,afade=t=in:st=0:d=0.5,afade=t=out:st=$FADE_V:d=0.5[voice];[0:a][voice]amix=inputs=2:duration=first:normalize=0[mix]"',
    '-map 0:v -map "[mix]" -c:v copy -c:a aac -b:a 192k -shortest -movflags +faststart',
    mixOutPath
  ].join(' ');
} else {
  // atempo auto-fit applies only to voice. Music stays at its own tempo (artistic).
  mixInner = [
    `VIDEO_DUR=$(/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${silentPath})`,
    '&&',
    `VOICE_DUR=$(/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${voicePath})`,
    '&&',
    'RATIO=$(awk "BEGIN{r=$VOICE_DUR/$VIDEO_DUR; if(r<1.0) r=1.0; if(r>1.10) r=1.10; printf \\"%.4f\\", r}")',
    '&&',
    'FADE_M=$(awk "BEGIN{f=$VIDEO_DUR-1.5; if(f<0) f=0; printf \\"%.3f\\", f}")',
    '&&',
    'FADE_V=$(awk "BEGIN{f=$VIDEO_DUR-0.5; if(f<0) f=0; printf \\"%.3f\\", f}")',
    '&&',
    '/usr/bin/ffmpeg -y -hide_banner -loglevel error',
    `-i ${silentPath} -i ${musicPath} -i ${voicePath}`,
    '-filter_complex "[1:a]volume=0.3,afade=t=out:st=$FADE_M:d=1.5[bg];[2:a]atempo=$RATIO,afade=t=in:st=0:d=0.5,afade=t=out:st=$FADE_V:d=0.5[voice];[0:a][bg][voice]amix=inputs=3:duration=first:normalize=0[mix]"',
    '-map 0:v -map "[mix]" -c:v copy -c:a aac -b:a 192k -shortest -movflags +faststart',
    mixOutPath
  ].join(' ');
}

// Stage 5 (optional) — avatar chromakey overlay. VERBATIM from CFTG/Combine - 9.json:
//   chromakey=0x79ff9b:0.12:0.05      — keys out the specific green Kling+matting produces
//   despill=type=green:mix=0.5        — removes green fringing on hair/edges
//   scale=400:-2                      — fixed agent width, auto-height preserving aspect (16:9 baseline)
//   overlay=W-w-40:H-h                — bottom-right corner, 40px right margin, flush with bottom edge
// ffmpeg re-encodes base (libx264 fast) because chromakey can't copy codec.
let overlayInner = '';
if (hasAvatar) {
  overlayInner = [
    `FADE_START=$(/usr/bin/ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${avatarPath} | awk '{f=$1-0.5; if(f<0) f=0; print f; exit}')`,
    '&&',
    '/usr/bin/ffmpeg -y -hide_banner -loglevel error',
    `-i ${preOverlayPath} -i ${avatarPath}`,
    `-filter_complex "[1:v]crop=iw*0.6:ih:iw*0.4:0,chromakey=0x79ff9b:0.10:0.05,despill=type=green:mix=0.5,scale=${AVATAR_SCALE}:-2,format=yuva420p,fade=t=out:st=\$FADE_START:d=0.5:alpha=1[agent];[0:v]scale=iw*sar:ih,setsar=1[base];[base][agent]overlay=W-w-40:H-h:eof_action=pass[v]"`,
    '-map "[v]" -map 0:a -c:v libx264 -preset fast -c:a copy -movflags +faststart',
    outPath
  ].join(' ');
}

const safeTitle = (row.title || 'montage').trim().replace(/[^\p{L}\p{N}_-]+/gu, '_').replace(/^_+|_+$/g, '').slice(0, 80) || 'montage';
const minioKey = `goodini-videos/${jobId}/${safeTitle}.mp4`;
const uploadInner = `mc cp --attr "Content-Disposition=attachment" ${outPath} minio/${minioKey} && (mc anonymous set download minio/goodini-videos >/dev/null 2>&1 || true)`;
const cleanupInner = `rm -rf ${tmpDir}`;

const docker = (inner) => `docker exec n8n-n8n-1 sh -c ${shq(inner)}`;

return [{ json: {
  valid: true,
  job_id: jobId,
  user_id: row.user_id,
  title: row.title || 'Untitled montage',
  clip_count: valid.length,
  has_music: hasMusic,
  has_voice: hasVoice,
  has_avatar: hasAvatar,
  tmp_dir: tmpDir,
  silent_path: silentPath,
  output_path: outPath,
  minio_key: minioKey,
  public_url: `https://s3.goodini.space/${minioKey}`,
  cmd_prepare: docker(prepareInner),
  cmd_ffmpeg: docker(renderInner),
  cmd_probe: docker(probeInner),
  cmd_download_music: downloadMusicInner ? docker(downloadMusicInner) : '',
  cmd_download_voice: downloadVoiceInner ? docker(downloadVoiceInner) : '',
  cmd_download_avatar: downloadAvatarInner ? docker(downloadAvatarInner) : '',
  cmd_mix: docker(mixInner),
  cmd_overlay: overlayInner ? docker(overlayInner) : '',
  cmd_upload: docker(uploadInner),
  cmd_cleanup: docker(cleanupInner)
} }];

const r = $json;
if (r.code !== 0) throw new Error(`Download failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`FFmpeg concat failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`Music download failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`Voice download failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`Audio mix failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`Avatar download failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`Avatar overlay failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
return $input.all();

const r = $json;
if (r.code !== 0) throw new Error(`ffprobe failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
const dur = parseFloat((r.stdout || '0').trim());
if (!isFinite(dur) || dur <= 0) throw new Error(`ffprobe returned invalid duration: '${r.stdout}'`);
return [{ json: { duration_seconds: Math.round(dur) } }];

const r = $json;
if (r.code !== 0) throw new Error(`Upload failed (exit ${r.code}): ${r.stderr || r.stdout || 'no output'}`);
const out = r.stdout || '';
if (/Total\s*\S*\s*0\s*B/i.test(out) && !/Transferred.*[1-9]/.test(out)) {
  throw new Error(`Upload wrote 0 bytes — source file was probably missing. mc output:\n${out}`);
}
return $input.all();
